    int val; 
    Node *left;
    Node *right;

    Node(int node_value) {
        val = node_value;
        left = right = NULL;
    }
}; */

class Solution {
    // Function to print leaf nodes of a binary tree
    void printLeaves(Node* root) {
        if (root == NULL)
            return;

        printLeaves(root->left);

        // Print it if it is a leaf node
        if (!root->left && !root->right)
            cout << root->val << " ";

        printLeaves(root->right);
    }

    // Function to print the left boundary nodes in TOP DOWN manner
    void printBoundaryLeft(Node* root) {
        if (!root)
            return;

        if (root->left) {
            // To ensure top-down order, print the node
            // before calling itself for the left subtree
            cout << root->val << " ";
            printBoundaryLeft(root->left);
        } else if (root->right) {
            cout << root->val << " ";
            printBoundaryLeft(root->right);
        }
        // Do nothing if it is a leaf node to avoid duplicates in output
    }

    // Function to print the right boundary nodes in BOTTOM UP manner
    void printBoundaryRight(Node* root) {
        if (!root)
            return;

        if (root->right) {
            // To ensure bottom-up order, first call for the right
            // subtree, then print this node
            printBoundaryRight(root->right);
            cout << root->val << " ";
        } else if (root->left) {
            printBoundaryRight(root->left);
            cout << root->val << " ";
        }
        // Do nothing if it is a leaf node to avoid duplicates in output
    }

  public:
    void printBoundary(Node* root) {
        if (root == NULL)
            return;

        cout << root->val << " ";

        // Print the left boundary in top-down manner.
        printBoundaryLeft(root->left);

        // Print all leaf nodes
        printLeaves(root->left);
        printLeaves(root->right);

        // Print the right boundary in bottom-up manner
        printBoundaryRight(root->right);
    }

};

