class Solution {
    // Function to print leaf nodes of a binary tree
    printLeaves(root) {
        if (root === null) return;

        this.printLeaves(root.left);

        // Print it if it is a leaf node
        if (root.left === null && root.right === null) {
            process.stdout.write(root.val + " ");
        }

        this.printLeaves(root.right);
    }

    // Function to print the left boundary nodes in TOP DOWN manner
    printBoundaryLeft(root) {
        if (root === null) return;

        if (root.left !== null) {
            // To ensure top-down order, print the node
            // before calling itself for the left subtree
            process.stdout.write(root.val + " ");
            this.printBoundaryLeft(root.left);
        } else if (root.right !== null) {
            process.stdout.write(root.val + " ");
            this.printBoundaryLeft(root.right);
        }
        // Do nothing if it is a leaf node to avoid duplicates in output
    }

    // Function to print the right boundary nodes in BOTTOM UP manner
    printBoundaryRight(root) {
        if (root === null) return;

        if (root.right !== null) {
            // To ensure bottom-up order, first call for the right
            // subtree, then print this node
            this.printBoundaryRight(root.right);
            process.stdout.write(root.val + " ");
        } else if (root.left !== null) {
            this.printBoundaryRight(root.left);
            process.stdout.write(root.val + " ");
        }
        // Do nothing if it is a leaf node to avoid duplicates in output
    }

    // Main function to print boundary of a binary tree
    printBoundary(root) {
        if (root === null) return;

        process.stdout.write(root.val + " ");

        // Print the left boundary in top-down manner.
        this.printBoundaryLeft(root.left);

        // Print all leaf nodes
        this.printLeaves(root.left);
        this.printLeaves(root.right);

        // Print the right boundary in bottom-up manner
        this.printBoundaryRight(root.right);
    }
}
